     6→
     7→export async function loadManifest(directory: string): Promise<Manifest> {
     8→  const manifestPath = path.join(directory, "inception.json");
     9→
    10→  let raw: string;
    11→  try {
    12→    raw = await readFile(manifestPath, "utf-8");
    13→  } catch {
    14→    throw new UserError(
    15→      "MANIFEST_INVALID",
    16→      `No inception.json found in ${directory}. Are you pointing to the right repo?`
    17→    );
    18→  }
    19→
    20→  let parsed: unknown;
    21→  try {
    22→    parsed = JSON.parse(raw);
    23→  } catch {
    24→    throw new UserError("MANIFEST_INVALID", `Invalid JSON in ${manifestPath}`);
    25→  }
    26→
    27→  return validateManifest(parsed, manifestPath);
    28→}
    29→
    30→function validateManifest(data: unknown, filePath: string): Manifest {
    31→  if (typeof data !== "object" || data === null || Array.isArray(data)) {
    32→    throw new UserError("MANIFEST_INVALID", `${filePath}: manifest must be a JSON object`);
    33→  }
    34→
    35→  const obj = data as Record<string, unknown>;
    36→
    37→  if (!Array.isArray(obj.skills)) {
    38→    throw new UserError("MANIFEST_INVALID", `${filePath}: "skills" must be an array`);
    39→  }
    40→
    41→  const skills: SkillEntry[] = obj.skills.map((entry: unknown, i: number) => {
    42→    if (typeof entry !== "object" || entry === null || Array.isArray(entry)) {
    43→      throw new UserError("MANIFEST_INVALID", `${filePath}: skills[${i}] must be an object`);
    44→    }
    45→
    46→    const skill = entry as Record<string, unknown>;
    47→
    48→    if (typeof skill.name !== "string" || skill.name.length === 0) {
    49→      throw new UserError("MANIFEST_INVALID", `${filePath}: skills[${i}].name must be a non-empty string`);
    50→    }
    51→
    52→    const SAFE_NAME_RE = /^[a-zA-Z0-9][a-zA-Z0-9._-]*$/;
    53→    if (!SAFE_NAME_RE.test(skill.name as string)) {
    54→      throw new UserError(
    55→        "MANIFEST_INVALID",
    56→        `${filePath}: skills[${i}].name must contain only letters, digits, hyphens, underscores, and dots, and must not start with a dot`
    57→      );
    58→    }
    59→
    60→    if (typeof skill.path !== "string" || skill.path.length === 0) {
    61→      throw new UserError("MANIFEST_INVALID", `${filePath}: skills[${i}].path must be a non-empty string`);
    62→    }
    63→
    64→    if (path.isAbsolute(skill.path as string)) {
    65→      throw new UserError("MANIFEST_INVALID", `${filePath}: skills[${i}].path must be a relative path`);
    66→    }
    67→
    68→    if (!Array.isArray(skill.agents) || skill.agents.length === 0) {
    69→      throw new UserError("MANIFEST_INVALID", `${filePath}: skills[${i}].agents must be a non-empty array`);
    70→    }
    71→
    72→    for (const agent of skill.agents) {
    73→      if (!AGENT_IDS.includes(agent as AgentId)) {
    74→        throw new UserError(
    75→          "MANIFEST_INVALID",
    76→          `${filePath}: skills[${i}].agents contains unknown agent "${agent}". Valid agents: ${AGENT_IDS.join(", ")}`
    77→        );
    78→      }
    79→    }
    80→
    81→    return {
    82→      name: skill.name,
    83→      path: skill.path,
    84→      agents: skill.agents as AgentId[],
    85→    };
    86→  });
    87→
    88→  return {
    89→    skills,
    90→    mcpServers: Array.isArray(obj.mcpServers) ? obj.mcpServers : [],
    91→    agentRules: Array.isArray(obj.agentRules) ? obj.agentRules : [],
    92→  };
    93→}
