     6→  yellow: "\x1b[33m",
     7→  cyan: "\x1b[36m",
     8→  reset: "\x1b[0m",
     9→} as const;
    10→
    11→type Color = keyof typeof C;
    12→
    13→export interface Logger {
    14→  fail(label: string, msg: string): void;
    15→  ok(label: string): void;
    16→  skip(label: string, note: string): void;
    17→  plan(label: string): void;
    18→  warn(label: string, msg: string): void;
    19→  info(msg: string): void;
    20→  error(msg: string): void;
    21→  errorRaw(value: unknown): void;
    22→  detail(msg: string): void;
    23→  silence(): void;
    24→}
    25→
    26→export function createLogger(): Logger {
    27→  let silent = false;
    28→  const tty = Boolean(process.stdout.isTTY);
    29→  const errTTY = Boolean(process.stderr.isTTY);
    30→
    31→  const c = (col: Color, text: string, onTTY: boolean): string =>
    32→    onTTY ? `${C[col]}${text}${C.reset}` : text;
    33→
    34→  return {
    35→    fail(label, msg) {
    36→      if (!silent) process.stderr.write(`  ${c("red", "✗", errTTY)} ${label}: ${msg}\n`);
    37→    },
    38→    ok(label) {
    39→      if (!silent) process.stdout.write(`  ${c("green", "✓", tty)} ${label}\n`);
    40→    },
    41→    skip(label, note) {
    42→      if (!silent) process.stdout.write(`  ${c("yellow", "-", tty)} ${label} ${note}\n`);
    43→    },
    44→    plan(label) {
    45→      if (!silent) process.stdout.write(`  ${c("cyan", "○", tty)} ${label}\n`);
    46→    },
    47→    warn(label, msg) {
    48→      if (!silent) process.stdout.write(`  ${c("yellow", "!", tty)} ${label}: ${msg}\n`);
    49→    },
    50→    info(msg) {
    51→      if (!silent) process.stdout.write(`${msg}\n`);
    52→    },
    53→    error(msg) {
    54→      if (!silent) process.stderr.write(`${msg}\n`);
    55→    },
    56→    errorRaw(value) {
    57→      if (!silent) console.error(value);
    58→    },
    59→    detail(msg) {
    60→      if (!silent) process.stdout.write(`    ${msg}\n`);
    61→    },
    62→    silence() {
    63→      silent = true;
    64→    },
    65→  };
    66→}
    67→
    68→export const logger = createLogger();
    69→
    70→export function dryRunPrefix(dryRun: boolean): string {
    71→  if (!dryRun) return "";
    72→  return Boolean(process.stdout.isTTY) ? `\x1b[36m[dry-run]\x1b[0m ` : `[dry-run] `;
    73→}
